import{_ as n,o as t,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"62. Demand Escalation Policy","description":"","frontmatter":{"title":"62. Demand Escalation Policy","eba":"Mental Health Services 2024-2028","topics":["consultation","union-matters"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/62-demand-escalation-policy.md","filePath":"ebas/mental-health/common-terms/staffing/62-demand-escalation-policy.md"}'),s={name:"ebas/mental-health/common-terms/staffing/62-demand-escalation-policy.md"};function i(r,e,p,l,c,d){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_62-demand-escalation-policy" tabindex="-1">62. Demand Escalation Policy <a class="header-anchor" href="#_62-demand-escalation-policy" aria-label="Permalink to &quot;62. Demand Escalation Policy&quot;">​</a></h1><p><strong>62.1</strong> Each Employer will maintain and apply a demand escalation policy in accordance with this clause no later than six months after the commencement of this Agreement.</p><p><strong>62.2</strong> Demand escalation policies will be developed and revised in consultation with Employees and the Unions.</p><p><strong>62.3</strong> Employers and the Union understand the potential impact unplanned increases in demand has on both patient and employee safety. The purpose of this clause is to promote:</p><p><strong>(a)</strong> safe patient care</p><p><strong>(b)</strong> staff safety; and</p><p><strong>(c)</strong> a risk management framework in managing an increase in demand.</p><p><strong>62.4</strong> Principles of policy</p><p><strong>(a)</strong> Health Services will experience unplanned increases in demand.</p><p><strong>(b)</strong> The appropriate planning and recording of escalation plans will assist in responding to such demand and in the process promote the health and safety of staff and patients.</p><p><strong>(c)</strong> Collaborative risk assessments should inform the development of such plans.</p><p><strong>(d)</strong> Employees need to have access to escalation plans and the process for implementing the escalation plan so there is minimum delay in the Health Service responding to increases in demand.</p><p><strong>(e)</strong> The operation of the escalation plan will be dependent on collaboration between Health Service nursing and midwifery senior managers and Ward/Unit Management on a shift-by-shift basis taking into account matters including occupancy and patient acuity.</p><p><strong>62.5</strong> Each Employer will have policies, developed in consultation with Employees and the Union, which set out the precise process to be followed to ensure patient and staff safety when:</p><p><strong>(a)</strong> service demand is approaching capacity</p><p><strong>(b)</strong> there is an identified risk to patient or employee safety.</p><p><strong>62.6</strong> The policy will have considered relevant risk assessments, in particular where circumstances require nursing care to be provided in an alternative environment, and relevant legislation, regulations or guidelines.</p><p><strong>62.7</strong> The policy will encapsulate the principles set out in subclause 62.4 above and contain specific information which sets out the following:</p><p><strong>(a)</strong> the trigger point(s) for the activation of the policy, noting that these trigger points should act as an early warning system</p><p><strong>(a)</strong> the accountabilities of those employees involved in the decision-making process</p><p><strong>(b)</strong> the process to be followed for those responsible for implementing the process, including the means to access additional, immediate and appropriate resources including appropriately qualified nursing staff</p><p><strong>(c)</strong> the identification of any alternative environment whereby Nursing care may be provided</p><p><strong>(d)</strong> the process for orientating staff to the alternative area and the requirement to perform a risk assessment in circumstances where one has not been completed; and</p><p><strong>(e)</strong> the de-escalation process.</p>',24)])])}const g=n(s,[["render",i]]);export{h as __pageData,g as default};
